  yPos += 5;
  doc.text(`Contact : ${contactInfo.mobile} E-Mail : ${contactInfo.email} www.reposenergy.com`, 105, yPos, { align: "center" });

  if (logoBase64) {
    doc.addImage(logoBase64, 'PNG', 160, 8, 35, 10);
