      amount = 0; // Not calculated per row for display anymore
    } else {
      amount = rate;
    }

    if (item.isAddon) {
      subtotalAddons += amount;
    } else {
      subtotalMainItem += amount;
    }

    totalRateSum += rate;

    const row = [
      (index + 1).toString(),
      item.desc,
      classification,
      item.hsn,
      item.quantity,
      formatIndianCurrency(rate)
    ];

    if (isInstallment) {
        row.push(item.tenure);
    }

    tableBody.push(row);
  });

  // --- DISCOUNT CALCULATION ---
  const discountPercent = data.discountPercentage || 0;
  const totalExWorks = totalRateSum;
  let discountAmount = 0;
  let netExWorks = totalExWorks;

  if (discountPercent > 0) {
    discountAmount = totalExWorks * (discountPercent / 100);
    netExWorks = totalExWorks - discountAmount;
  }

  let cgst = 0, sgst = 0, igst = 0;
  let totalIncl = 0;
  let downPaymentGST = 0;
  let grandTotal = 0;

  if (!isInstallment) {
    // Outright: Calculate 18% Tax on Net Amount
    const taxableAmount = netExWorks;
    if (isMaharashtra) {
      cgst = taxableAmount * 0.09;
      sgst = taxableAmount * 0.09;
    } else {
      igst = taxableAmount * 0.18;
    }
    totalIncl = taxableAmount + cgst + sgst + igst;
    grandTotal = totalIncl;

    // Summary Rows
    tableBody.push(["", "Ex-Works Total(INR)", "", "", "", formatIndianCurrency(totalExWorks)]);

    if (discountPercent > 0) {
      tableBody.push(["", `Discount (${discountPercent}%)`, "", "", "", `-${formatIndianCurrency(discountAmount)}`]);
      tableBody.push(["", "Net Ex-Works", "", "", "", formatIndianCurrency(netExWorks)]);
    }

    tableBody.push(["", "GST @18%", "", "", "", formatIndianCurrency(totalIncl)]);
    tableBody.push(["", "Round Off", "", "", "", "0"]);
    tableBody.push(["", "Total (INR)", "", "", "", formatIndianCurrency(totalIncl)]);

  } else {
    // Installment Summary
    const monthlyExWorks = totalRateSum; // Monthly Rate

    // For installment, if discount is applied, it applies to monthly rental
    // Recalculate based on discounted monthly
    const monthlyDiscountAmount = monthlyExWorks * (discountPercent / 100);
    const netMonthly = monthlyExWorks - monthlyDiscountAmount;

    downPaymentGST = netMonthly * 36 * 0.18; // GST on total contract value (36 months) derived from net monthly
    grandTotal = netMonthly; // Display Monthly

    tableBody.push(["", "Ex-Works Total(INR)", "", "", "", formatIndianCurrency(monthlyExWorks), ""]);

    if (discountPercent > 0) {
      tableBody.push(["", `Discount (${discountPercent}%)`, "", "", "", `-${formatIndianCurrency(monthlyDiscountAmount)}`, ""]);
      tableBody.push(["", "Net Monthly Ex-Works", "", "", "", formatIndianCurrency(netMonthly), ""]);
    }

    tableBody.push(["", "Down Payment (GST @18%)", "", "", "", formatIndianCurrency(downPaymentGST), ""]);
    tableBody.push(["", "Round Off", "", "", "", "0", ""]);
    tableBody.push([
      "", 
      "Total (INR)", 
      "", 
      "", 
      "",
      formatIndianCurrency(netMonthly), 
      "36 Months"
    ]);
  }

  doc.autoTable({
    startY: yPos,
    head: [columns],
    body: tableBody,
    theme: 'grid',
    margin: { left: 10, right: 10 }, 
    styles: {
      font: "helvetica", fontSize: 6.5, textColor: black, lineColor: [0, 0, 0], lineWidth: 0.1, valign: 'top', cellPadding: 1, overflow: 'linebreak'
    },
    headStyles: {
      fillColor: [255, 255, 255], textColor: black, fontStyle: 'bold', lineWidth: 0.1, lineColor: [0, 0, 0],
    },
    columnStyles: columnStyles,
    didParseCell: function (data: any) {
      // Bold summary rows
      if (data.row.index >= (tableBody.length - (discountPercent > 0 ? (isInstallment ? 5 : 5) : (isInstallment ? 3 : 3)))) {
         data.cell.styles.fontStyle = 'bold';
      }
      // Bold "Addon" classification
      if (data.section === 'body' && data.column.index === 2 && data.cell.raw === 'Addon') {
         data.cell.styles.fontStyle = 'bold';
      }
    }
  });

  // @ts-ignore
  let finalY = doc.lastAutoTable.finalY;

  if (!isInstallment) {
    doc.setFont("helvetica", "bold");
    doc.setFontSize(9);
    doc.text(`Amount (Words) - Rs. ${numberToWords(Math.round(grandTotal))} Only`, 10, finalY + 6);
    finalY += 10;
  } else {
    finalY += 6;
  }

  if (finalY < 280) {
    doc.rect(5, finalY, 200, 287 - finalY - 5);
    doc.line(140, finalY, 140, 287 - 5);
    doc.setFontSize(9);
    doc.setFont("helvetica", "italic");
    doc.text("Note: This is a business proposal.", 7, finalY + 10);
    doc.setFont("helvetica", "bold");
    doc.text("For Repos Energy India Private Limited", 142, finalY + 5);
    doc.text("Authorised Signatory", 160, 287 - 10, { align: "center" });
  }

  // --- PAGE 2: TERMS AND CONDITIONS ---
  doc.addPage();
  doc.rect(5, 5, 200, 287);
  let tY = 20;
  doc.setFont("helvetica", "bold");
  doc.setFontSize(11);
  doc.text("TERMS AND CONDITIONS (ANNEXURE)", 105, tY, { align: 'center' });
  doc.line(5, tY + 2, 205, tY + 2);
  tY += 10;
  doc.setFontSize(9);
  doc.setFont("helvetica", "normal");

  const addPoint = (title: string, content: string) => {
     doc.setFont("helvetica", "bold");
     doc.text(title, 10, tY);
     tY += 4;
     doc.setFont("helvetica", "normal");
     const splitText = doc.splitTextToSize(content, 185);
     doc.text(splitText, 10, tY);
     tY += (splitText.length * 4) + 4;
     if (tY > 270) {
         doc.addPage();
         doc.rect(5, 5, 200, 287);
         tY = 20;
     }
  };

  // A. USAGE
  addPoint("A. USE:", "The Repos Portable Station (“RPS”) is for internal business use of storing and dispensing high speed diesel only (in line with approval from PESO) and the RPS shall not be used for any other purpose. Customer shall not use RPS for refueling any third party vehicle or for the purpose of reselling of high speed diesel to any third party vehicle; since such use of RPS will be in contravention of Motor Spirit And High Speed Diesel (Regulation Of Supply, Distribution And Prevention Of Malpractices) Order, 2005 as amended from time to time, for which the only Customer will be liable.");

  // B. WORK ORDER
  addPoint("B. WORK ORDER:", "The Customer shall place the order only in the name of Repos IoT India Private Limited (“The Company”). Any discrepancy in the name shall result in cancellation of order. Upon initiation of the work order, no modification regarding RPS variant model or any other related upgrades will be accepted.");

  // C. TITLE TRANSFER
  addPoint("C. TITLE TRANSFER & DELIVERY:", "RPS shall be ready for delivery at Delivery Location (defined hereunder) within twelve (12) weeks from the date of execution of the purchase order, subject to the fulfilment of payment terms mentioned in Point D. below and prior approvals from the governmental organizations. The title of the said RPS shall stand transferred from Repos IoT India Private Limited (hereinafter referred to as \"Repos\") to the Customer upon dispatch of the said RPS from Repos' manufacturing facility situated at Chakan, Pune, Maharashtra, India. Upon such transfer of title, save and except as expressly provided herein, all obligations pertaining to the RPS shall stand transferred from Repos to the Customer, and Repos shall stand discharged from all obligations relating to the RPS, except those explicitly specified herein. Subsequent to the transfer of title, the Customer shall be solely responsible and liable for any non-compliance or deviation from the Standard Operating Procedures (SOPs), regulations promulgated by relevant authorities, and statutory compliances prescribed by the Petroleum and Explosives Safety Organization (PESO), Oil Marketing Companies (OMCs), or any other concerned regulatory or governing bodies. Repos shall, on a best effort basis, undertake the installation of the RPS within fifteen (15) business days from the date of dispatch subject to the site readiness, which timeline is indicative and shall not be construed as a mandatory obligation upon Repos.");

  // D. PAYMENT TERMS
  doc.setFont("helvetica", "bold");
  doc.text("D. PAYMENT TERMS:", 10, tY);
  tY += 4;
  doc.setFont("helvetica", "normal");

  const paymentContent = "Payment shall be made by the Customer to Repos as per Table 1 mentioned hereunder. The dispatch shall be scheduled only after the complete payment is received by Repos. The said dispatch of RPS would be in accordance with Ex-Workshop (EXW) basis at Waki, Chakan Pune (Maharashtra).\n\nRepos shall make the RPS available for collection by the Buyer on an EXW basis from Repos’ facility located in Waki, Chakan, Pune, Maharashtra (\"Delivery Location\") and the Customer shall be solely responsible for all costs, risks, and liabilities associated with transportation, loading, insurance and any other expenses incurred after the goods have been made available at the Delivery Location. Upon notification of readiness for pickup, Customer shall take delivery within seven (7) days, failing which storage charges may apply at the Repos’ discretion. Title and risk in the goods shall pass to the Buyer upon collection from the Delivery Location read with Point C. TITLE TRANSFER & DELIVERY above.";

  const splitPaymentText = doc.splitTextToSize(paymentContent, 185);
  doc.text(splitPaymentText, 10, tY);
  tY += (splitPaymentText.length * 4) + 2;

  // Only show Table 1 if NOT installment
  if (!isInstallment) {
      if (tY > 250) {
          doc.addPage();
          doc.rect(5, 5, 200, 287);
          tY = 20;
      }
      doc.setFont("helvetica", "bold");
      doc.text("Table 1", 10, tY + 4);
      tY += 6;
      doc.autoTable({
          startY: tY,
          head: [["Payment Schedule", "Amount"]],
          body: [
              ["Prior Approval Application", "INR 5,00,000/-"],
              ["Start of Manufacturing", "INR 20,00,000/-"],
              ["Before Dispatch", "Balance Amount"]
          ],
          theme: 'grid',
          tableWidth: 120,
          margin: { left: 10 },
          styles: { fontSize: 8, cellPadding: 2 },
          headStyles: { fillColor: [220, 220, 220], textColor: black, fontStyle: 'bold' }
      });
      // @ts-ignore
      tY = doc.lastAutoTable.finalY + 8;
  } else {
      tY += 4;
  }

  // E. GST
  addPoint("E. PAYMENT OF GOODS & SERVICE TAX (GST):", "GST will be applicable on RPS at prevailing rates at the time of dispatch & GST rate is subject to change, any revisions will automatically be applied.");

  // F. INSPECTION
  addPoint("F. INSPECTION:", "Prior to dispatch, RPS shall be inspected by the Inspection Team and/or the Customer or its authorized representative to ensure compliance with the agreed specifications and quality standards. The inspection shall take place at the Repos’ facility, and the Customer shall have the right to verify RPS’s condition before acceptance. Any concerns or discrepancies identified during the inspection shall be addressed before shipment.");

  // G. WARRANTY
  addPoint("G. WARRANTY:", "The RPS is covered under a twelve (12) month warranty from the date of dispatch, against manufacturing and craftsmanship defects. This warranty does not cover any damages resulting from mishandling, physical damage due to accidents, operator negligence, improper maintenance, unauthorized modifications, or repairs attempted by any third party other than authorized representatives of Repos.\n\nOnce the RPS has been dispatched from Repos' facility or title has been transferred, Repos shall not be liable for any loss or damage.");

  // H. CUSTOMER SCOPE
  const customerScopeText = "1. Civil & Electrical Work: Any civil, electrical, or additional work required for the installation and functioning of the RPS shall be the sole responsibility of the Customer.\n2. Fraudulent Activities: Repos shall not be liable for any fraudulent activities conducted by the Customer in connection with any services provided through RPS.\n3. Additional Costs: The Customer shall bear all costs related to: a) transportation of RPS; b) Insurance; c) nozzle or any other yearly renewals;\n4. Unloading Responsibility: The Customer shall be responsible for unloading RPS at their designated site.\n5. Cancellation after invoicing incurs a cancellation fee. Repos may levy a fee on the Customer for cancellation of order post invoicing.\n6. Fuel Procurement and Quality/Quantity: The Customer shall be solely responsible for procuring High-Speed Diesel (HSD) from authorized Oil Marketing Companies (OMCs) , in compliance with all applicable laws and regulations. The Customer shall be exclusively liable to verify and ensure the quality and quantity of the HSD so procured. Repos shall have no responsibility or liability, whether direct or indirect, in relation to the procurement, quality, or quantity of the fuel purchased by the Customer, nor for any losses, claims, or damages arising therefrom.";
  addPoint("H. CUSTOMER SCOPE:", customerScopeText);

  // I. IP
  addPoint("I. INTELLECTUAL PROPERTIES (“IP”):", "All intellectual properties and proprietary technology of Company remains absolute property of the Company and under no condition the Customer shall have any right on the IP. The Customer shall not copy or reverse-engineer the RMD or any software.");

  // J. APPLICABILITY
  addPoint("J. APPLICABILITY OF TERMS AND CONDITIONS:", "Unless otherwise expressly agreed in writing, these Terms and Conditions shall apply to all contracts, and engagements between Customer and Repos for the sale of RPS and all related services provided by Repos, into which contracts are incorporated by reference.");

  doc.save(`${proposalNo}.pdf`);
};

import React, { useState, useEffect } from 'react';
import { CONSUMPTION_OPTIONS } from '../constants';
import type { CustomerDetails } from '../types';
import { submitLead } from '../services/api';

interface LeadFormModalProps {
  onSubmit: (data?: CustomerDetails) => void;
  loggedInUser?: string | null;
  initialData?: CustomerDetails | null;
}

const INDUSTRY_OPTIONS = [
  'Mining',
  'Logistics',
  'Infra & Construction',
  'Manufacturing',
  'Others'
];

const STATE_OPTIONS = [
  'Andhra Pradesh', 'Arunachal Pradesh', 'Assam', 'Bihar', 'Chhattisgarh', 'Goa', 'Gujarat', 
  'Haryana', 'Himachal Pradesh', 'Jharkhand', 'Karnataka', 'Kerala', 'Madhya Pradesh', 
  'Maharashtra', 'Manipur', 'Meghalaya', 'Mizoram', 'Nagaland', 'Odisha', 'Punjab', 
  'Rajasthan', 'Sikkim', 'Tamil Nadu', 'Telangana', 'Tripura', 'Uttar Pradesh', 'Uttarakhand', 
  'West Bengal',
  'Andaman and Nicobar Islands', 'Chandigarh', 'Dadra and Nagar Haveli and Daman and Diu', 
  'Delhi', 'Jammu and Kashmir', 'Ladakh', 'Lakshadweep', 'Puducherry'
].sort();

const SALESPERSON_OPTIONS = [
  'Ajay Kumar',
  'Ketan Sarode',
  'Burhan Cyclewala',
  'Malvika Sharma',
  'Chetan Walunj',
  'Aditi Walunj'
];

const LeadFormModal: React.FC<LeadFormModalProps> = ({ onSubmit, loggedInUser, initialData }) => {
  const [formData, setFormData] = useState<CustomerDetails>({
    name: '',
    mobile: '',
    email: '',
    company: '',
    industry: '',
    state: '',
    consumption: '',
    salesperson: '',
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // If we have initial data (e.g. editing for quote), use it
    if (initialData) {
      setFormData(initialData);
      return;
    }

    // Otherwise apply default logic for new form (e.g. match logged in user to salesperson)
    if (loggedInUser) {
      const match = SALESPERSON_OPTIONS.find(opt => 
        opt.toLowerCase().startsWith(loggedInUser.toLowerCase())
      );
      if (match) {
        setFormData(prev => ({ ...prev, salesperson: match }));
      }
    }
  }, [loggedInUser, initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;

    // Clear error when user starts typing in mobile field
    if (name === 'mobile') {
      setError(null);
    }

    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const validateForm = (): boolean => {
    // Mobile Validation: Exactly 10 digits
    const mobileRegex = /^\d{10}$/;
    if (!mobileRegex.test(formData.mobile)) {
      setError('Mobile number must be exactly 10 digits.');
      return false;
    }
    return true;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateForm()) {
      return;
    }

    setIsSubmitting(true);
    setError(null);

    try {
      // Call backend API service
      await submitLead(formData);
      // On success, pass data up to parent
      onSubmit(formData);
    } catch (err) {
      console.error(err);
      setError("Failed to submit. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div
      className="fixed inset-0 bg-black bg-opacity-50 backdrop-blur-[10px] flex items-center justify-center z-[100] p-4 animate-fade-in"
    >
      <div
        className="bg-white rounded-lg shadow-2xl border border-gray-200 w-full max-w-[772px] relative p-6 md:p-12 overflow-y-auto max-h-full"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Close button enabled for testing purposes */}
        <button 
          onClick={() => onSubmit()} 
          className="absolute top-6 right-6 text-gray-400 hover:text-gray-800 disabled:opacity-50 z-10" 
          aria-label="Close"
          disabled={isSubmitting}
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
        <h2 className="text-2xl md:text-3xl font-semibold mb-2 text-left text-gray-900">Partner with Repos</h2>
        <p className="text-sm text-gray-600 mb-6 text-left">
          Please provide your details to initiate your journey with Repos. This information helps us tailor the perfect Fuel Distribution Solution for your business needs.
        </p>

        {error && (
          <div className="mb-4 p-3 bg-red-50 text-red-600 border border-red-200 rounded-md text-sm">
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit}>
          <div className="space-y-4 mb-6">
            {/* Row 1: Name | Mobile */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-x-6">
              <div>
                <label htmlFor="name" className="block text-sm font-medium text-gray-700 mb-1">Name</label>
                <input
                  type="text"
                  name="name"
                  id="name"
                  value={formData.name}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-2 bg-gray-100 border border-gray-300 rounded-md focus:ring-1 focus:ring-gray-400 outline-none transition"
                  placeholder="Your full name"
                />
              </div>
              <div>
                <label htmlFor="mobile" className="block text-sm font-medium text-gray-700 mb-1">Mobile Number</label>
                <input
                  type="tel"
                  name="mobile"
                  id="mobile"
                  value={formData.mobile}
                  onChange={handleChange}
                  required
                  maxLength={10}
                  pattern="[0-9]{10}"
                  className={`w-full px-4 py-2 bg-gray-100 border rounded-md focus:ring-1 outline-none transition ${error && error.includes('Mobile') ? 'border-red-500 focus:ring-red-500' : 'border-gray-300 focus:ring-gray-400'}`}
                  placeholder="e.g., 9876543210"
                />
              </div>
            </div>

            {/* Row 2: Email | Salesperson */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-x-6">
              <div>
                <label htmlFor="email" className="block text-sm font-medium text-gray-700 mb-1">Email ID</label>
                <input
                  type="email"
                  name="email"
                  id="email"
                  value={formData.email}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-2 bg-gray-100 border border-gray-300 rounded-md focus:ring-1 focus:ring-gray-400 outline-none transition"
                  placeholder="you@example.com"
                />
              </div>
              <div>
                <label htmlFor="salesperson" className="block text-sm font-medium text-gray-700 mb-1">Repos Representative</label>
                <select
                  name="salesperson"
                  id="salesperson"
                  value={formData.salesperson}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-1 focus:ring-gray-400 outline-none transition appearance-none bg-gray-100"
                  style={{
                    backgroundImage: `url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' fill='none' viewBox='0 0 20 20'%3e%3cpath stroke='%236b7280' stroke-linecap='round' stroke-linejoin='round' stroke-width='1.5' d='M6 8l4 4 4-4'/%3e%3c/svg%3e")`,
                    backgroundPosition: 'right 0.5rem center',
                    backgroundRepeat: 'no-repeat',
                    backgroundSize: '1.5em 1.5em',
                  }}
                >
                  <option value="" disabled>Select Repos Representative</option>
                  {SALESPERSON_OPTIONS.map(option => (
                    <option key={option} value={option}>{option}</option>
                  ))}
                </select>
              </div>
            </div>

            {/* Row 3: Company | Industry */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-x-6">
              <div>
                <label htmlFor="company" className="block text-sm font-medium text-gray-700 mb-1">Company Name</label>
                <input
                  type="text"
                  name="company"
                  id="company"
                  value={formData.company}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-2 bg-gray-100 border border-gray-300 rounded-md focus:ring-1 focus:ring-gray-400 outline-none transition"
                  placeholder="Your company's name"
                />
              </div>
              <div>
                <label htmlFor="industry" className="block text-sm font-medium text-gray-700 mb-1">Industry</label>
                <select
                  name="industry"
                  id="industry"
                  value={formData.industry}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-2 bg-gray-100 border border-gray-300 rounded-md focus:ring-1 focus:ring-gray-400 outline-none transition appearance-none"
                  style={{
                    backgroundImage: `url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' fill='none' viewBox='0 0 20 20'%3e%3cpath stroke='%236b7280' stroke-linecap='round' stroke-linejoin='round' stroke-width='1.5' d='M6 8l4 4 4-4'/%3e%3c/svg%3e")`,
                    backgroundPosition: 'right 0.5rem center',
                    backgroundRepeat: 'no-repeat',
                    backgroundSize: '1.5em 1.5em',
                  }}
                >
                  <option value="" disabled>Select Industry</option>
                  {INDUSTRY_OPTIONS.map(option => (
                    <option key={option} value={option}>{option}</option>
                  ))}
                </select>
              </div>
            </div>

            {/* Row 4: State | Consumption */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-x-6">
              <div>
                <label htmlFor="state" className="block text-sm font-medium text-gray-700 mb-1">State / UT</label>
                <select
                  name="state"
                  id="state"
                  value={formData.state}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-2 bg-gray-100 border border-gray-300 rounded-md focus:ring-1 focus:ring-gray-400 outline-none transition appearance-none"
                  style={{
                    backgroundImage: `url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' fill='none' viewBox='0 0 20 20'%3e%3cpath stroke='%236b7280' stroke-linecap='round' stroke-linejoin='round' stroke-width='1.5' d='M6 8l4 4 4-4'/%3e%3c/svg%3e")`,
                    backgroundPosition: 'right 0.5rem center',
                    backgroundRepeat: 'no-repeat',
                    backgroundSize: '1.5em 1.5em',
                  }}
                >
                  <option value="" disabled>Select State</option>
                  {STATE_OPTIONS.map(option => (
                    <option key={option} value={option}>{option}</option>
                  ))}
                </select>
              </div>
              <div>
                <label htmlFor="consumption" className="block text-sm font-medium text-gray-700 mb-1">Monthly Consumption</label>
                <select
                  name="consumption"
                  id="consumption"
                  value={formData.consumption}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-2 bg-gray-100 border border-gray-300 rounded-md focus:ring-1 focus:ring-gray-400 outline-none transition appearance-none"
                  style={{
                    backgroundImage: `url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' fill='none' viewBox='0 0 20 20'%3e%3cpath stroke='%236b7280' stroke-linecap='round' stroke-linejoin='round' stroke-width='1.5' d='M6 8l4 4 4-4'/%3e%3c/svg%3e")`,
                    backgroundPosition: 'right 0.5rem center',
                    backgroundRepeat: 'no-repeat',
                    backgroundSize: '1.5em 1.5em',
                  }}
                >
                  <option value="" disabled>Select Consumption</option>
                  {CONSUMPTION_OPTIONS.map(option => (
                    <option key={option} value={option}>{option}</option>
                  ))}
                </select>
              </div>
            </div>
          </div>
          <div className="pt-2">
            <button
              type="submit"
              disabled={isSubmitting}
              className={`w-full bg-blue-600 text-white font-bold py-3 px-8 rounded-lg transition-all duration-300 focus:outline-none focus:ring-2 focus:ring-blue-600 focus:ring-offset-2 hover:scale-105 ${isSubmitting ? 'opacity-70 cursor-not-allowed' : 'hover:bg-blue-700'}`}
            >
              {isSubmitting ? 'Submitting...' : 'Submit'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default LeadFormModal;

import React, { useState, useMemo, useEffect } from 'react';
import Header from './components/Header';
import CarVisualizer from './components/CarVisualizer';
import Configurator from './components/Configurator';
import LeadFormModal from './components/LeadFormModal';
import LoginModal from './components/LoginModal';
import LandingPage from './components/LandingPage';
import ExplorePage from './components/ExplorePage';
import FaqPage from './components/FaqPage';
import ReposPayPage from './components/ReposPayPage';
import AboutUsPage from './components/AboutUsPage';
import ComparisonModal from './components/ComparisonModal';
import { generateQuotePDF } from './utils/pdfGenerator';
import { logQuoteGeneration } from './services/api';
import type { AccessoryOption, IotOption, TankOption, DispensingUnitOption, SafetyUpgradeOption, CustomerDetails, LicenseOption, QuoteData } from './types';
import { 
  TANK_OPTIONS,
} from './constants';
import { getRecommendedTankId } from './utils/vehicleHelpers';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'landing' | 'app' | 'explore' | 'faq' | 'reposPay' | 'about'>('landing');

  const [isLoginModalOpen, setIsLoginModalOpen] = useState(true);
  const [userRole, setUserRole] = useState<'sales' | 'guest' | null>(null);
  const [loggedInUserId, setLoggedInUserId] = useState<string | null>(null);

  const [isLeadFormOpen, setIsLeadFormOpen] = useState(false);
  const [customerDetails, setCustomerDetails] = useState<CustomerDetails | null>(null);
  const [showRoiCalculator, setShowRoiCalculator] = useState(false);

  // Modal States
  const [isComparisonModalOpen, setIsComparisonModalOpen] = useState(false);

  // Track if we are waiting for lead form submission to generate a quote
  const [pendingQuoteGeneration, setPendingQuoteGeneration] = useState(false);

  // Discount Feature State
  const [isDiscountModalOpen, setIsDiscountModalOpen] = useState(false);
  const [discountPercentage, setDiscountPercentage] = useState(0);

  const [paymentMode, setPaymentMode] = useState<'outright' | 'installments'>('installments');

  // Selected Tank - Base product remains selected
  const [selectedTank, setSelectedTank] = useState<TankOption['id']>(() => 
    TANK_OPTIONS[0]?.id || '22kl'
  );

  // Selection States
  const [selectedReposOsOptions, setSelectedReposOsOptions] = useState<AccessoryOption[]>([]);
  const [selectedMechanicalInclusionOptions, setSelectedMechanicalInclusionOptions] = useState<AccessoryOption[]>([]);
  const [selectedDecantation, setSelectedDecantation] = useState<IotOption[]>([]);
  const [selectedDispensingUnits, setSelectedDispensingUnits] = useState<DispensingUnitOption[]>([]);
  const [selectedSafetyUnits, setSelectedSafetyUnits] = useState<AccessoryOption[]>([]);
  const [selectedSafetyUpgrades, setSelectedSafetyUpgrades] = useState<SafetyUpgradeOption[]>([]);
  const [selectedLicenseOptions, setSelectedLicenseOptions] = useState<LicenseOption[]>([]);
  const [rfidTagsQuantity, setRfidTagsQuantity] = useState<number>(0);

  const [selectedConsumption, setSelectedConsumption] = useState<string | null>(null);
  const [recommendedTankId, setRecommendedTankId] = useState<TankOption['id'] | null>(null);

  // Compute if we should show the capacity platform preview
  const showCapacityPreview = useMemo(() => {
    const addOnCount = 
      selectedReposOsOptions.length + 
      selectedMechanicalInclusionOptions.length + 
      selectedDecantation.length + 
      selectedDispensingUnits.length + 
      selectedSafetyUnits.length + 
      selectedSafetyUpgrades.length +
      (rfidTagsQuantity > 0 ? 1 : 0);

    return addOnCount === 0;
  }, [
    selectedReposOsOptions, 
    selectedMechanicalInclusionOptions, 
    selectedDecantation, 
    selectedDispensingUnits, 
    selectedSafetyUnits, 
    selectedSafetyUpgrades,
    rfidTagsQuantity
  ]);

  useEffect(() => {
    const s3BaseUrl = 'https://drf-media-data.s3.ap-south-1.amazonaws.com/compressor_aws/ShortPixelOptimized/';
    const imageCount = 31;
    const imageUrls = Array.from({ length: imageCount }, (_, i) => `${s3BaseUrl}${i + 1}.png`);

    imageUrls.forEach(url => {
      const img = new Image();
      img.src = url;
    });
  }, []);

  const handleLogin = (role: 'sales' | 'guest', userId?: string) => {
    setUserRole(role);
    if (userId) setLoggedInUserId(userId);
    setIsLoginModalOpen(false);
    setIsLeadFormOpen(true);
  };

  const handleConsumptionSelect = (consumption: string) => {
    setSelectedConsumption(consumption);
    const recId = getRecommendedTankId(consumption);
    setRecommendedTankId(recId);
  };

  const handleTankChange = (tankId: TankOption['id']) => {
    setSelectedTank(tankId);
  };

  const handleReposOsToggle = (option: AccessoryOption) => {
    setSelectedReposOsOptions(prev =>
      prev.find(o => o.id === option.id)
        ? prev.filter(o => o.id !== option.id)
        : [...prev, option]
    );
  };

  const handleMechanicalInclusionToggle = (option: AccessoryOption) => {
    setSelectedMechanicalInclusionOptions(prev =>
      prev.find(o => o.id === option.id)
        ? prev.filter(o => o.id !== option.id)
        : [...prev, option]
    );
  };

  const handleDecantationToggle = (option: IotOption) => {
    setSelectedDecantation(prev =>
      prev.find(o => o.id === option.id)
        ? prev.filter(o => o.id !== option.id)
        : [...prev, option]
    );
  };

  const handleSafetyUnitToggle = (option: AccessoryOption) => {
    setSelectedSafetyUnits(prev =>
      prev.find(o => o.id === option.id)
        ? prev.filter(o => o.id !== option.id)
        : [...prev, option]
    );
  };

  const handleSafetyUpgradeToggle = (option: SafetyUpgradeOption) => {
    setSelectedSafetyUpgrades(prev => {
      const exists = prev.find(o => o.id === option.id);
      if (!exists) {
        return [...prev, option];
      }
      return prev.filter(o => o.id !== option.id);
    });
  };

  const handleDispensingUnitToggle = (option: DispensingUnitOption) => {
    setSelectedDispensingUnits(prev => 
      prev.find(o => o.id === option.id)
        ? prev.filter(o => o.id !== option.id)
        : [...prev, option]
    );
  };

  const resetConfiguration = () => {
    setSelectedTank(TANK_OPTIONS[0]?.id || '22kl');
    setSelectedReposOsOptions([]);
    setSelectedMechanicalInclusionOptions([]);
    setSelectedDecantation([]);
    setSelectedDispensingUnits([]);
    setSelectedSafetyUnits([]);
    setSelectedSafetyUpgrades([]);
    setSelectedLicenseOptions([]);
    setRfidTagsQuantity(0);
    setPaymentMode('installments');
    setDiscountPercentage(0);
  };

  const monthlyTotalPrice = useMemo(() => {
    const tank = TANK_OPTIONS.find(t => t.id === selectedTank);
    const tankPrice = tank ? tank.price : 0;

    let price = tankPrice;
    price += selectedDispensingUnits.reduce((sum, du) => sum + du.price, 0);
    price += selectedReposOsOptions.reduce((total, opt) => total + opt.price, 0);
    price += selectedMechanicalInclusionOptions.reduce((total, totalOpt) => total + totalOpt.price, 0);
    price += selectedDecantation.reduce((total, opt) => total + opt.price, 0);
    price += selectedSafetyUnits.reduce((total, unit) => total + unit.price, 0);
    price += selectedSafetyUpgrades.reduce((total, unit) => total + unit.price, 0);
    price += selectedLicenseOptions.reduce((total, opt) => total + opt.price, 0);
    // Add RFID Tags cost: 49 per tag per month
    price += (rfidTagsQuantity * 49);
    return price;
  }, [selectedTank, selectedDispensingUnits, selectedReposOsOptions, selectedMechanicalInclusionOptions, selectedDecantation, selectedSafetyUnits, selectedSafetyUpgrades, selectedLicenseOptions, rfidTagsQuantity]);

  const totalContractValue = useMemo(() => {
    return monthlyTotalPrice * 36;
  }, [monthlyTotalPrice]);

  const gstAmount = useMemo(() => {
    return totalContractValue * 0.18;
  }, [totalContractValue]);

  const totalInclTax = useMemo(() => {
    return totalContractValue + gstAmount;
  }, [totalContractValue, gstAmount]);

  const displayPrice = useMemo(() => {
    if (paymentMode === 'outright') {
      return totalInclTax;
    }
    return monthlyTotalPrice;
  }, [totalInclTax, monthlyTotalPrice, paymentMode]);

  const showPrices = userRole === 'sales';

  const handleLeadFormClose = async (details?: CustomerDetails) => {
    setIsLeadFormOpen(false);

    if (details) {
      setCustomerDetails(details);
      setSelectedConsumption(details.consumption);

      const recId = getRecommendedTankId(details.consumption);
      setRecommendedTankId(recId);

      // Check if we need to generate a quote
      if (pendingQuoteGeneration) {
        const quoteData: QuoteData = {
          customerDetails: details,
          paymentMode,
          totalPrice: displayPrice,
          gstAmount: gstAmount,
          totalContractValue: totalContractValue,
          monthlyPrice: paymentMode === 'installments' ? displayPrice : undefined,
          rfidTagsQuantity,
          discountPercentage,
          configuration: {
            tank: selectedTank,
            dispensingUnits: selectedDispensingUnits,
            decantation: selectedDecantation,
            accessories: {
              reposOs: selectedReposOsOptions,
              mechanical: selectedMechanicalInclusionOptions,
              safetyUnits: selectedSafetyUnits,
              safetyUpgrades: selectedSafetyUpgrades,
            },
            licenses: selectedLicenseOptions,
          }
        };

        await generateQuotePDF(quoteData);
        logQuoteGeneration(quoteData);
        setPendingQuoteGeneration(false);
      }
    } else {
      // User closed without submitting
      setPendingQuoteGeneration(false);
    }
  };

  const handleEnterApp = () => {
    setCurrentView('app');
    setShowRoiCalculator(false);
  };

  if (currentView === 'landing') {
    return (
      <LandingPage 
        onEnterApp={handleEnterApp} 
        onExploreClick={() => setCurrentView('explore')}
        onFaqClick={() => setCurrentView('faq')}
        onReposPayClick={() => setCurrentView('reposPay')}
        onAboutClick={() => setCurrentView('about')}
        onRoiClick={() => {
          setCurrentView('app');
          setShowRoiCalculator(true);
        }}
      />
    );
  }

  if (currentView === 'explore') {
    return (
      <ExplorePage 
        onNavigateHome={() => setCurrentView('landing')}
        onNavigateToApp={handleEnterApp}
        onFaqClick={() => setCurrentView('faq')}
        onAboutClick={() => setCurrentView('about')}
      />
    );
  }

  if (currentView === 'faq') {
    return (
      <FaqPage 
        onBack={() => setCurrentView('landing')} 
        onAboutClick={() => setCurrentView('about')}
      />
    );
  }

  if (currentView === 'reposPay') {
    return (
      <ReposPayPage 
        onBack={() => setCurrentView('landing')}
        onNavigateToApp={handleEnterApp}
        onAboutClick={() => setCurrentView('about')}
      />
    );
  }

  if (currentView === 'about') {
    return (
      <AboutUsPage
        onNavigateHome={() => setCurrentView('landing')}
        onNavigateToApp={handleEnterApp}
        onExploreClick={() => setCurrentView('explore')}
        onReposPayClick={() => setCurrentView('reposPay')}
      />
    );
  }

  return (
    <div className="min-h-screen bg-stone-50 font-sans text-gray-800 relative">
      {isLoginModalOpen && <LoginModal onLogin={handleLogin} />}
      {isLeadFormOpen && <LeadFormModal onSubmit={handleLeadFormClose} loggedInUser={loggedInUserId} initialData={customerDetails} />}

      <Header 
        navItems={['Home']}
        onRoiClick={() => setShowRoiCalculator(true)} 
        onHomeClick={() => setShowRoiCalculator(false)}
        rightNavItems={['FAQs']}
        onNavItemClick={(item) => {
            if (item === 'FAQs') setCurrentView('faq');
            if (item === 'Home') setCurrentView('landing');
        }}
        onSecretClick={() => setIsDiscountModalOpen(true)}
      />

      {showRoiCalculator ? (
        <div className="w-full h-[calc(100vh-72px)] bg-white">
          <iframe 
            src="https://repos-rps-roi-calculator.vercel.app/" 
            className="w-full h-full border-0"
            title="ROI Calculator"
          />
        </div>
      ) : (
        <main className="flex flex-col lg:flex-row">
          <div className="w-full lg:flex-1 lg:h-[calc(100vh-72px)] lg:sticky lg:top-[72px] h-[45vh] min-h-[300px] relative z-0 bg-gray-100">
            <CarVisualizer 
              tank={selectedTank}
              mechanicalOptions={selectedMechanicalInclusionOptions}
              dispensingUnits={selectedDispensingUnits}
              safetyUnits={selectedSafetyUnits}
              safetyUpgrades={selectedSafetyUpgrades}
              decantation={selectedDecantation}
              hasPlatform={showCapacityPreview}
            />
          </div>
          <div className="w-full lg:w-[400px] xl:w-[450px] lg:h-[calc(100vh-72px)] bg-white z-10 flex-shrink-0">
            <Configurator
              customerDetails={customerDetails}
              paymentMode={paymentMode}
              setPaymentMode={setPaymentMode}
              selectedTank={selectedTank}
              setSelectedTank={handleTankChange}
              selectedReposOsOptions={selectedReposOsOptions}
              onReposOsToggle={handleReposOsToggle}
              selectedMechanicalInclusionOptions={selectedMechanicalInclusionOptions}
              onMechanicalInclusionToggle={handleMechanicalInclusionToggle}

              selectedDecantation={selectedDecantation}
              onDecantationToggle={handleDecantationToggle}

              selectedDispensingUnits={selectedDispensingUnits}
              onDispensingUnitToggle={handleDispensingUnitToggle}

              selectedSafetyUnits={selectedSafetyUnits}
              onSafetyUnitToggle={handleSafetyUnitToggle}
              selectedSafetyUpgrades={selectedSafetyUpgrades}
              onSafetyUpgradeToggle={handleSafetyUpgradeToggle}
              selectedLicenseOptions={selectedLicenseOptions}

              rfidTagsQuantity={rfidTagsQuantity}
              setRfidTagsQuantity={setRfidTagsQuantity}

              selectedConsumption={selectedConsumption}
              onConsumptionSelect={handleConsumptionSelect}

              totalContractValue={totalContractValue}
              gstAmount={gstAmount}
              finalPrice={displayPrice}

              recommendedTankId={recommendedTankId}
              showPrices={showPrices}
              onResetConfiguration={resetConfiguration}

              onOpenComparison={() => setIsComparisonModalOpen(true)}
              onOpenQuote={() => {
                setPendingQuoteGeneration(true);
                setIsLeadFormOpen(true);
              }}
              onCalculateRoi={() => setShowRoiCalculator(true)}
            />
          </div>
        </main>
      )}

      {isComparisonModalOpen && (
        <ComparisonModal onClose={() => setIsComparisonModalOpen(false)} showPrices={showPrices} />
      )}

      {isDiscountModalOpen && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center bg-black bg-opacity-60 backdrop-blur-sm p-4 animate-fade-in">
          <div className="bg-white p-8 rounded-2xl shadow-2xl w-full max-w-sm border border-gray-100">
            <div className="mb-6">
              <label className="block text-sm font-medium text-gray-700 mb-2">Value</label>
              <input
                type="number"
                min="0"
                max="100"
                value={discountPercentage}
                onChange={(e) => setDiscountPercentage(Math.min(100, Math.max(0, Number(e.target.value))))}
                className="w-full bg-white border border-gray-300 p-3 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none text-lg font-semibold"
                autoFocus
              />
            </div>
            <div className="flex justify-end gap-3">
              <button 
                onClick={() => setIsDiscountModalOpen(false)} 
                className="px-6 py-2.5 bg-gray-100 text-gray-700 font-semibold rounded-lg hover:bg-gray-200 transition-colors"
              >
                Cancel
              </button>
              <button 
                onClick={() => setIsDiscountModalOpen(false)} 
                className="px-6 py-2.5 bg-blue-600 text-white font-semibold rounded-lg hover:bg-blue-700 transition-colors shadow-sm"
              >
                Apply
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

